module.exports=[226150,a=>{"use strict";let b=[{slug:"prijs-renovatie-zoersel",title:"Wat kost renovatie in Zoersel in 2026?",excerpt:"Prijsrichtlijnen voor renovatie in Zoersel: van ramen en gevel tot totaalrenovatie en slimme fasering.",description:"Ontdek wat renovatie in Zoersel kost in 2026. Inclusief prijsvoorbeelden voor ramen, gevelrenovatie en totaalrenovatie, plus de factoren die uw budget beïnvloeden.",date:"2026-03-12",readTime:"7 min",category:"Prijzen",keywords:["prijs renovatie zoersel","renovatie zoersel prijs","totaalrenovatie zoersel","aannemer zoersel"],serviceTags:["renovatie","totaalrenovatie","ramen-deuren","gevelrenovatie"],cityTags:["zoersel"],dynamic:!0,intro:"Wie zoekt op renovatie Zoersel wil meestal geen algemene richtprijzen, maar een realistisch budget voor een woning in de eigen regio. In deze gids zetten we de belangrijkste prijsblokken op een rij en leggen we uit hoe u werken slim kunt faseren.",keyPoints:["Gerichte renovatiewerken: vanaf ongeveer €8.000","Gevelrenovatie met isolatie: vaak €80 tot €150 per m²","Nieuwe ramen en deuren: afhankelijk van materiaal, glas en aantal openingen","Totaalrenovatie: budget wordt bepaald door technieken, afwerking en volgorde van de werken"],sections:[{title:"Welke renovatiewerken worden het vaakst gecombineerd in Zoersel?",paragraphs:["In Zoersel zien we vaak renovatieprojecten waarbij de buitenschil centraal staat: nieuwe ramen en deuren, gevelisolatie, crepi of een grotere totaalrenovatie waarin ook binnenafwerking wordt meegenomen.","Omdat veel woningen in en rond Zoersel vrijstaand of halfopen zijn, loont het meestal om niet alleen naar één onderdeel te kijken. Wie ramen, gevel en algemene renovatiewerken samen bekijkt, haalt doorgaans een beter resultaat op vlak van comfort, EPC en planning."],bullets:["Ramen en deuren vervangen om warmteverlies en tocht te beperken","Gevelrenovatie met isolatie om de buitenschil energetisch te verbeteren","Gefaseerde renovatie waarbij budget per fase wordt bewaakt"]},{title:"Richtprijzen per type werk",paragraphs:["Voor kleinere renovatiewerken of een duidelijke eerste fase start het budget vaak vanaf een paar duizend euro, maar zodra meerdere onderdelen samenkomen, stijgt de kost snel door voorbereiding, materiaal en afwerking.","Nieuwe ramen en deuren worden geprijsd op basis van materiaal, glas, afmetingen en afwerking. Gevelrenovatie hangt vooral af van oppervlakte, isolatiedikte, herstelwerk en gekozen afwerking. Bij totaalrenovatie spelen technieken, afbraak, planning en binnenafwerking een veel grotere rol."],bullets:["Ramen en deuren: prijs hangt sterk af van PVC of aluminium en het aantal openingen","Gevelrenovatie: reken op een prijs per m², afhankelijk van herstel en isolatie","Totaalrenovatie: budget op projectbasis met duidelijke fases en keuzes"]},{title:"Wat duwt het budget omhoog?",paragraphs:["De grootste budgetversnellers zijn bijna altijd verborgen gebreken, bijkomende voorbereidende werken en te late beslissingen tijdens de uitvoering. Daarom is een goede opname vooraf essentieel.","Ook materiaalkeuze maakt een groot verschil. Aluminium ramen, zwaardere isolatiepakketten of een hogere afwerkingsgraad zijn logisch wanneer de woning en het doel dat vragen, maar ze moeten wel in verhouding staan tot het totale project."]},{title:"Hoe houdt u renovatie in Zoersel financieel beheersbaar?",paragraphs:["De meest efficiënte aanpak is meestal starten met de buitenschil: ramen, deuren, gevel en isolatie. Daarna volgen technieken en binnenafwerking. Zo vermijdt u dat afgewerkte ruimtes later opnieuw open moeten.","Vraag ook altijd naar scenario's. Een offerte met een basisaanpak, een energetische upgrade en een totaaltraject maakt het eenvoudiger om het juiste evenwicht te vinden tussen investering en rendement."]},{title:"Wanneer is een offerte echt bruikbaar?",paragraphs:["Een bruikbare offerte is meer dan een totaalprijs. Ze splitst materialen, voorbereiding, uitvoering en afwerking op, en ze maakt duidelijk welke keuzes nog openstaan.","Voor renovatie in Zoersel is het zinvol om zowel de werken op korte termijn als de logische volgende fase mee te bespreken. Dat voorkomt dat u vandaag goedkopere keuzes maakt die later extra kosten veroorzaken."]}],ctaTitle:"Renovatie in Zoersel bespreken?",ctaText:"Yannova bekijkt graag welke combinatie van ramen, gevel en renovatiewerken voor uw woning in Zoersel het meeste effect geeft.",relatedSlugs:["prijs-renovatie-zoersel","energie-renovatie-premie-belgie","hoeveel-kost-gevelrenovatie"]},{slug:"ramen-vervangen-prijs-antwerpen",title:"Ramen vervangen prijs in Antwerpen: waar moet u op rekenen?",excerpt:"Wat kost ramen vervangen in Antwerpen, welke factoren bepalen de prijs en wanneer loont PVC of aluminium?",description:"Ontdek de prijs van ramen vervangen in Antwerpen. We bekijken materiaal, glas, plaatsing, stadswoningen en slimme keuzes voor renovatieprojecten.",date:"2026-03-12",readTime:"6 min",category:"Prijzen",keywords:["ramen vervangen prijs antwerpen","ramen antwerpen prijs","pvc ramen antwerpen","aluminium ramen antwerpen"],serviceTags:["ramen-deuren"],cityTags:["antwerpen","deurne","merksem"],dynamic:!0,intro:"Bij ramen vervangen in Antwerpen is de context minstens even belangrijk als het product zelf. Stadspanden, rijwoningen en appartementen vragen een andere voorbereiding dan een vrijstaande woning, en dat ziet u ook terug in de prijs.",keyPoints:["PVC is meestal de meest budgetvriendelijke keuze","Aluminium wordt vaak gekozen bij grotere glaspartijen en strakkere architectuur","Plaatsing in stedelijke context vraagt extra aandacht voor bereikbaarheid en afwerking","Goede ramen leveren niet alleen comfort op, maar ook winst op EPC en geluidsdemping"],sections:[{title:"Welke prijsfactoren zijn in Antwerpen doorslaggevend?",paragraphs:["De kost van ramen vervangen in Antwerpen wordt vooral bepaald door materiaal, beglazing, afmetingen, bereikbaarheid en de staat van de bestaande openingen.","Bij stadswoningen zien we vaker extra werk rond afbraak, transport, beperkte toegang en afwerking. Daardoor ligt de prijs niet alleen vast in het raam zelf, maar ook in de plaatsingscontext."]},{title:"PVC of aluminium: wanneer kiest u wat?",paragraphs:["PVC is bijzonder sterk als u prijs, isolatie en onderhoudsgemak wilt combineren. Voor veel rijwoningen en renovatieprojecten in Antwerpen blijft het de meest rationele keuze.","Aluminium wordt interessanter bij grotere raamoppervlaktes, slanke profielen en een meer architecturale uitstraling. Het prijsverschil is reëel, maar kan verantwoord zijn wanneer lichtinval en design zwaarder wegen."],bullets:["PVC: sterk op budget, isolatie en onderhoud","Aluminium: sterk op design, glasoppervlak en strakke afwerking","De juiste keuze hangt af van woningtype, gewenste stijl en totaalbudget"]},{title:"Wat zit meestal in de prijs inbegrepen?",paragraphs:["Een goede prijsinschatting omvat meer dan de levering van nieuwe ramen. Demontage van oude profielen, transport, plaatsing, aansluiting, afwerking en eventuele dorpels of vensterbanken bepalen mee het totale plaatje.","Vraag daarom altijd na wat exact inbegrepen is. Een scherpe prijs zonder degelijke afwerking of duidelijke plaatsingsmethode is zelden de beste investering."]},{title:"Wanneer loont ramen vervangen het meest?",paragraphs:["Ramen vervangen loont het hardst wanneer bestaande profielen tocht veroorzaken, de beglazing verouderd is of de gevel toch al aangepakt wordt. In die gevallen vermijdt u dubbel werk en verbetert u de woning in één beweging.","In Antwerpen wordt ramen vervangen ook vaak gekoppeld aan geluidscomfort. Zeker aan drukkere assen maken betere profielen en glas een voelbaar verschil."]},{title:"Hoe vraagt u een correcte offerte aan?",paragraphs:["Geef naast afmetingen ook context mee: woningtype, verdieping, bereikbaarheid en gewenste afwerking. Dat helpt om sneller een bruikbare en realistische offerte te krijgen.","Wie twijfelt tussen PVC en aluminium doet er goed aan beide scenario's naast elkaar te laten prijzen. Zo vergelijkt u niet alleen de investering, maar ook het effect op comfort en uitstraling."]}],ctaTitle:"Prijs voor ramen vervangen in Antwerpen kennen?",ctaText:"Yannova maakt graag een duidelijke prijsinschatting voor uw woning in Antwerpen, Deurne, Merksem of omliggende buurten.",relatedSlugs:["wat-kosten-nieuwe-ramen","pvc-of-aluminium-ramen","premies-ramen-deuren-2026"]},{slug:"crepi-gevel-voordelen",title:"Crepi gevel voordelen: wanneer is crepi de juiste keuze?",excerpt:"De voordelen van crepi op een rij: uitstraling, isolatie, onderhoud en de situaties waarin crepi echt loont.",description:"Ontdek de voordelen van een crepi gevel. Wanneer is crepi slim, hoe combineert u het met isolatie en waar moet u op letten bij afwerking en onderhoud?",date:"2026-03-12",readTime:"6 min",category:"Advies",keywords:["crepi gevel voordelen","crepi gevel","voordelen crepi","gevelrenovatie crepi"],serviceTags:["crepi-gevel","gevelrenovatie"],dynamic:!0,intro:"Crepi is populair omdat het tegelijk een esthetische en technische oplossing kan zijn. U geeft uw woning een nieuwe uitstraling, en als u crepi combineert met buitenisolatie verbetert u ook de energieprestatie van de gevel.",keyPoints:["Crepi geeft een bestaande woning snel een strakke, hedendaagse uitstraling","De afwerking combineert goed met buitenisolatie","Een correcte opbouw en detailafwerking zijn bepalend voor duurzaamheid","Crepi is vooral interessant wanneer gevelbeeld en energieprestatie samen belangrijk zijn"],sections:[{title:"Waarom kiezen zoveel eigenaars voor crepi?",paragraphs:["Crepi maakt het mogelijk om een verouderde gevel visueel volledig te vernieuwen zonder de woning structureel te veranderen. Dat is een groot voordeel bij renovaties waar de basis nog goed is, maar de gevel gedateerd oogt.","Bovendien laat crepi zich perfect combineren met buitenisolatie. Daardoor is het niet alleen een esthetische keuze, maar ook een functionele investering in comfort en energieverbruik."]},{title:"Welke voordelen merkt u in de praktijk?",paragraphs:["Het eerste voordeel is uitstraling. Een woning met een goed afgewerkte crepi-gevel oogt meteen verzorgd en eigentijds. Daarnaast voelt de woning vaak comfortabeler aan wanneer de gevel tegelijk geïsoleerd wordt.","Ook onderhoud speelt mee. Een kwalitatieve crepi-opbouw met aangepaste detaillering rond dorpels, plinten en aansluitingen blijft lang mooi en is relatief eenvoudig proper te houden."],bullets:["Nieuwe uitstraling zonder volledige heropbouw van de gevel","Combineerbaar met gevelisolatie voor beter EPC","Minder warmteverlies en meer wooncomfort","Kleur- en structuurkeuze afgestemd op de woning"]},{title:"Wanneer is crepi minder geschikt?",paragraphs:["Crepi is niet voor elke gevel automatisch de beste oplossing. Wanneer de ondergrond instabiel is, er zware vochtproblemen spelen of het architecturale karakter van de woning om een andere afwerking vraagt, moet eerst technisch bekeken worden wat haalbaar is.","Daarom is een plaatsbezoek cruciaal. Het gaat niet alleen om kleur en look, maar om de volledige opbouw van de gevel en de kwaliteit van de detaillering."]},{title:"Wat bepaalt de levensduur?",paragraphs:["De duurzaamheid van crepi zit in de voorbereiding: correcte isolatieplaten, een degelijke wapening, de juiste basislagen en zorgvuldige afwerking aan alle randen en aansluitingen.","Ook waterafvoer is essentieel. Slechte detaillering aan vensterbanken, dakranden of plinten is een veel grotere risicofactor dan het crepi-materiaal zelf."]},{title:"Hoe maakt u de juiste keuze?",paragraphs:["Bekijk crepi altijd in functie van de totale woning. Past het bij de architectuur, wilt u tegelijk isoleren en is een strakke buitenafwerking een prioriteit? Dan is crepi vaak een zeer sterke optie.","Laat altijd een scenario vergelijken met en zonder isolatie. Zo ziet u meteen wat het verschil is in investering, uitstraling en energetische winst."]}],ctaTitle:"Twijfelt u of crepi bij uw gevel past?",ctaText:"Yannova bekijkt graag ter plaatse of crepi, gevelisolatie of een bredere gevelrenovatie de juiste stap is voor uw woning.",relatedSlugs:["hoeveel-kost-gevelrenovatie","renovatie-vergunning-antwerpen","energie-renovatie-premie-belgie"]},{slug:"renovatie-vergunning-antwerpen",title:"Renovatie vergunning Antwerpen: wanneer moet u opletten?",excerpt:"Niet elke renovatie in Antwerpen vraagt een vergunning, maar bij gevelwijzigingen en grotere werken is voorbereiding cruciaal.",description:"Lees wanneer u in Antwerpen een vergunning of meldingsplicht moet bekijken bij renovatie, gevelwerken, ramen en totaalprojecten.",date:"2026-03-12",readTime:"6 min",category:"Advies",keywords:["renovatie vergunning antwerpen","gevelrenovatie vergunning antwerpen","omgevingsvergunning renovatie antwerpen"],serviceTags:["renovatie","totaalrenovatie","gevelrenovatie","ramen-deuren"],cityTags:["antwerpen"],dynamic:!0,intro:"Bij renovatie in Antwerpen is technische voorbereiding niet genoeg. Zeker in stedelijke context moet u ook goed inschatten of een omgevingsvergunning, melding of voorafgaand advies nodig is.",keyPoints:["Interne werken zijn vaak eenvoudiger dan zichtbare wijzigingen aan de gevel","Ramen, deuren en gevelaanpassingen aan straatzijde vragen extra aandacht","Ook beschermd erfgoed of specifieke zones kunnen de regels verstrengen","Een goede voorbereiding voorkomt stilstand en herwerk"],sections:[{title:"Welke renovaties zijn meestal eenvoudig?",paragraphs:["Veel zuiver interne vernieuwingen vallen buiten de zwaardere vergunningsplicht, zolang u geen structurele of stedenbouwkundige wijzigingen doorvoert. Denk aan afwerking, beperkte vernieuwing of het vervangen van technieken zonder impact op het uitzicht van de woning.","Zodra de buitenschil verandert of het volume aangepast wordt, stijgt de kans dat u regels, meldingen of vergunningen moet bekijken."]},{title:"Waar zitten de gevoeligste punten in Antwerpen?",paragraphs:["Gevelwijzigingen aan de straatzijde, ingrepen aan ramen en deuren die het uitzicht veranderen, uitbreidingen en ingrepen in beschermde of gevoelige zones verdienen altijd extra aandacht.","In Antwerpen speelt ook de stedelijke context mee. Wat in een randgemeente sneller kan, vraagt in de stad soms bijkomend overleg of een andere uitwerking."],bullets:["Wijziging van uitzicht aan straatzijde","Grotere ingrepen aan volume of dak","Werken in zones met erfgoed- of beeldkwaliteitsregels"]},{title:"Waarom is dit ook belangrijk voor prijs en planning?",paragraphs:["Een vergunningstraject of bijkomende voorbereiding heeft impact op de timing. Daarom moet dit vroeg in het project bekeken worden, zeker als meerdere werken samenlopen.","Wie pas tijdens de uitvoering vaststelt dat een aanpassing niet zomaar kan, riskeert vertraging, bijkomende kosten en wijzigingen in materiaal of detailafwerking."]},{title:"Hoe pakt u dit praktisch aan?",paragraphs:["Werk met duidelijke foto's, beschrijf de bestaande toestand en wees concreet over wat u wil aanpassen. Bij ramen en deuren is het bijvoorbeeld nuttig om exact aan te geven of het uitzicht, de indeling of de kleur verandert.","Voor grotere trajecten is het verstandig om eerst een technisch en stedenbouwkundig haalbaar scenario vast te leggen, en pas daarna de uitvoering te plannen."]},{title:"Wat kan Yannova hierin betekenen?",paragraphs:["Yannova begeleidt renovatieprojecten praktisch: we bekijken welke werken logisch samen horen, waar de gevoeligheden zitten en welke voorbereiding nodig is om zonder verrassingen te starten.","Voor Antwerpen is die voorbereiding extra waardevol, omdat timing, bereikbaarheid en regelgeving samen het verschil maken tussen een vlot project en een stilgevallen planning."]}],ctaTitle:"Renovatieproject in Antwerpen opstarten?",ctaText:"We bekijken graag samen welke werken technisch en praktisch logisch zijn, en waar u vooraf rekening mee moet houden.",relatedSlugs:["prijs-renovatie-zoersel","crepi-gevel-voordelen","ramen-vervangen-prijs-antwerpen"]},{slug:"energie-renovatie-premie-belgie",title:"Energie renovatie premie België: welke werken leveren het meeste op?",excerpt:"Niet elke premie is even interessant. Dit zijn de renovatiewerken die meestal het sterkste rendement geven op comfort en subsidie.",description:"Overzicht van energiegerichte renovatiepremies in België en Vlaanderen, en welke werken meestal het meeste opleveren voor eigenaars.",date:"2026-03-12",readTime:"7 min",category:"Premies",keywords:["energie renovatie premie belgië","renovatie premie belgie","mijn verbouwpremie","premie ramen deuren gevel"],serviceTags:["renovatie","ramen-deuren","gevelrenovatie","crepi-gevel","totaalrenovatie"],dynamic:!0,intro:"Premies zijn interessant, maar ze zijn zelden de enige reden om te renoveren. De echte winst zit in de combinatie van subsidie, lager verbruik, meer comfort en een sterkere woningwaarde.",keyPoints:["Buitenschilwerken geven meestal de grootste combinatie van subsidie en energiewinst","Ramen, deuren en gevelisolatie zijn vaak de eerste logische stap","Premies zijn pas interessant als de technische oplossing ook echt bij de woning past","Een goede volgorde van werken voorkomt dat u subsidie misloopt of dubbel werk betaalt"],sections:[{title:"Waarom eerst naar de buitenschil kijken?",paragraphs:["Bij veel woningen zit de grootste energetische winst in ramen, deuren, gevel en isolatie. Dat zijn ook precies de werken die vaak in aanmerking komen voor premie-ondersteuning.","Wie eerst de buitenschil op orde zet, krijgt niet alleen meer comfort, maar vermijdt ook dat latere investeringen minder efficiënt worden door warmteverlies of verouderde openingen."]},{title:"Welke werken leveren meestal het meeste op?",paragraphs:["Nieuwe ramen en deuren zijn sterk wanneer de bestaande profielen verouderd zijn of de beglazing nog zwak presteert. Gevelisolatie en crepi worden interessant wanneer de woning veel warmte verliest via de buitenmuren en de uitstraling tegelijk een upgrade mag krijgen.","In grotere trajecten maakt totaalrenovatie het mogelijk om meerdere premiegeschikte werken logisch te bundelen, maar dan is de volgorde en documentatie extra belangrijk."],bullets:["Ramen en deuren voor comfort, geluidsdemping en energieverlies","Gevelisolatie en crepi voor een sterke buitenschil","Gefaseerde renovatie om premie en planning slim te combineren"]},{title:"Wanneer krijgt premie te veel aandacht?",paragraphs:["Een premie mag nooit de enige reden zijn om voor een bepaald systeem of materiaal te kiezen. Soms is een oplossing die technisch beter past bij de woning uiteindelijk interessanter, ook als de subsidie beperkter is.","Daarom is goed advies belangrijk: eerst bekijken wat de woning nodig heeft, daarna zien hoe premie daar logisch op aansluit."]},{title:"Hoe voorkomt u dat u kansen mist?",paragraphs:["Bewaar offertes, facturen en technische info zorgvuldig. Werk ook met een duidelijke planning zodat premies, uitvoering en eventuele bijkomende fases op elkaar afgestemd blijven.","Voor wie meerdere ingrepen plant, is het vaak interessanter om vooraf het totaalplaatje te bekijken in plaats van per onderdeel ad hoc te beslissen."]},{title:"Wat is de slimste volgorde?",paragraphs:["Meestal begint een slim traject met ramen, deuren en/of gevel. Daarna volgen technieken en binnenafwerking. Zo bouwt u eerst de energieprestatie en het comfort op, en daarna de rest van de woning.","Dat is precies de reden waarom lokale SEO-pagina&apos;s voor ramen, gevelrenovatie en totaalrenovatie elkaar intern moeten versterken: ze horen inhoudelijk ook echt samen."]}],ctaTitle:"Wilt u weten welke premiegericht renovatiepad logisch is?",ctaText:"Yannova helpt u graag prioriteiten te leggen tussen ramen, gevel, isolatie en bredere renovatiewerken.",relatedSlugs:["premies-ramen-deuren-2026","hoeveel-kost-gevelrenovatie","prijs-renovatie-zoersel"]},{slug:"crepi-prijs-per-m2",title:"Crepi prijs per m²: wat kost gevelbepleistering in 2026?",excerpt:"Wat kost crepi per m² in 2026? Overzicht van prijzen voor crepi zonder en met isolatie, plus factoren die de prijs bepalen.",description:"Ontdek de prijs van crepi per m² in 2026. Van €40/m² voor enkel crepi tot €150/m² voor ETICS met isolatie. Inclusief premie-info.",date:"2026-03-13",readTime:"6 min",category:"Prijzen",keywords:["crepi prijs per m2","crepi prijs","gevelbepleistering prijs","crepi kosten","crepi antwerpen prijs"],serviceTags:["crepi-gevel","gevelrenovatie"],dynamic:!0,intro:"De prijs van crepi hangt sterk af van wat er onder zit. Enkel crepi op een bestaande gevel is een heel ander verhaal dan een volledig ETICS-systeem met isolatieplaten. In deze gids zetten we de prijsblokken op een rij.",keyPoints:["Enkel crepi (zonder isolatie): gemiddeld €40–€70 per m²","Crepi met buitenisolatie (ETICS): gemiddeld €80–€150 per m²","Voorbereiding en herstelwerk kunnen de prijs significant beïnvloeden","Mijn VerbouwPremie kan een deel van de kosten terugbetalen"],sections:[{title:"Wat bepaalt de prijs van crepi?",paragraphs:["De grootste prijsfactor is of u enkel crepi aanbrengt of tegelijk isoleert. Bij een ETICS-systeem (isolatieplaten + wapening + crepi) is de investering hoger, maar de energiewinst en premie-opbrengst zijn dat ook.","Daarnaast spelen de staat van de bestaande gevel, de oppervlakte, de toegankelijkheid (steigers of hoogtewerker) en de gekozen textuur en kleur een rol in de eindprijs."],bullets:["Type systeem: enkel crepi vs. ETICS met isolatie","Staat van de ondergrond: herstelwerk verhoogt de kostprijs","Oppervlakte en complexiteit van de gevel","Steigerkosten bij hogere gevels"]},{title:"Prijsoverzicht crepi per m² in 2026",paragraphs:["Voor enkel crepi op een voorbereide, stabiele ondergrond rekent u gemiddeld €40 tot €70 per m². Dit omvat de basislaag, wapening en afwerklaag, maar geen isolatie.","Een volledig ETICS-systeem met EPS-isolatieplaten (60–120mm) en crepi-afwerking kost gemiddeld €80 tot €150 per m². De exacte prijs hangt af van de isolatiedikte, het type crepi en de voorbereiding."],bullets:["Enkel crepi: €40–€70/m²","ETICS met 60mm EPS + crepi: €80–€110/m²","ETICS met 100–120mm EPS + crepi: €110–€150/m²","Steenstrips i.p.v. crepi: +€20–€40/m² extra"]},{title:"Wanneer loont de investering het meest?",paragraphs:["Crepi met isolatie loont het meest wanneer de woning veel warmte verliest via de buitenmuren en de gevel toch al aan vernieuwing toe is. U combineert dan een esthetische upgrade met een energetische verbetering.","Wie enkel crepi overweegt zonder isolatie, doet dat vaak om een verouderde of beschadigde gevel te vernieuwen. Dat is zinvol, maar het is de moeite om ook het isolatiescenario te laten berekenen."]},{title:"Premies voor crepi en gevelisolatie",paragraphs:["Via de Vlaamse Mijn VerbouwPremie kunt u een deel van de kosten voor buitenmuurisolatie recupereren. De voorwaarde is dat de isolatielaag minimaal Rd 3 m²K/W haalt, wat overeenkomt met ongeveer 80–100mm EPS.","Wij bezorgen u alle nodige attesten en facturen zodat uw premieaanvraag vlot verloopt. Vraag ook naar de Mijn VerbouwLening voor een voordelig rentetarief."]},{title:"Hoe vraagt u een correcte offerte aan?",paragraphs:["Geef bij uw aanvraag de oppervlakte van de te behandelen gevels mee, de staat van de bestaande gevel en of u ook wilt isoleren. Zo krijgt u een realistische en vergelijkbare offerte.","Vraag altijd twee scenario's: enkel crepi en crepi met isolatie. Het prijsverschil is kleiner dan veel mensen denken, maar het verschil in energiewinst en premie is groot."]}],ctaTitle:"Prijs voor crepi op uw woning kennen?",ctaText:"Yannova komt ter plaatse opmeten en bezorgt u een gedetailleerde offerte voor crepi, gevelisolatie of een complete gevelrenovatie.",relatedSlugs:["hoeveel-kost-gevelrenovatie","crepi-gevel-voordelen","energie-renovatie-premie-belgie"]},{slug:"gevelisolatie-prijs-voordelen",title:"Gevelisolatie prijs en voordelen: wat levert buitenmuurisolatie op?",excerpt:"Wat kost gevelisolatie en wat levert het op? Overzicht van prijzen, energiewinst en premies voor buitenmuurisolatie in 2026.",description:"Ontdek de prijs en voordelen van gevelisolatie in 2026. ETICS-systemen vanaf €80/m², tot 30% energiebesparing en Mijn VerbouwPremie.",date:"2026-03-13",readTime:"7 min",category:"Advies",keywords:["gevelisolatie prijs","buitenmuurisolatie prijs","gevelisolatie voordelen","gevelisolatie kosten","gevelisolatie antwerpen"],serviceTags:["gevelrenovatie","crepi-gevel"],dynamic:!0,intro:"Gevelisolatie is een van de meest effectieve energetische ingrepen voor woningen met ongeïsoleerde buitenmuren. U stopt warmteverlies, verbetert uw EPC en geeft de gevel tegelijk een nieuwe uitstraling.",keyPoints:["Buitenmuurisolatie vermindert warmteverlies via de gevel met 20–35%","ETICS-systemen kosten gemiddeld €80–€150 per m²","Mijn VerbouwPremie dekt een deel van de kosten","Geen verlies van binnenruimte, in tegenstelling tot binnenmuuisolatie"],sections:[{title:"Waarom is gevelisolatie zo effectief?",paragraphs:["Bij woningen zonder gevelisolatie gaat 20 tot 35% van de warmte verloren via de buitenmuren. Dat is na het dak de grootste bron van warmteverlies. Buitengevelisolatie pakt dit direct aan.","Bovendien verbetert gevelisolatie ook het zomercomfort: de woning warmt minder snel op bij hoge temperaturen, wat de behoefte aan koeling vermindert."]},{title:"Welke systemen bestaan er?",paragraphs:["Het meest gebruikte systeem is ETICS (External Thermal Insulation Composite System): isolatieplaten worden op de gevel gelijmd en verankerd, daarna afgewerkt met crepi, steenstrips of spuitkurk.","De keuze van isolatiemateriaal (EPS, minerale wol, PIR) en dikte bepaalt de thermische prestatie en de prijs. EPS is het meest betaalbaar; minerale wol is dampopen en brandwerend."],bullets:["EPS (geëxpandeerd polystyreen): meest betaalbaar, goede isolatiewaarden","Minerale wol: dampopen, brandwerend, iets duurder","PIR: hoogste isolatiewaarde per cm, interessant bij beperkte ruimte"]},{title:"Wat kost gevelisolatie per m²?",paragraphs:["Een volledig ETICS-systeem met EPS en crepi-afwerking kost gemiddeld €80 tot €150 per m², afhankelijk van isolatiedikte, afwerking en staat van de bestaande gevel.","Minerale wol is iets duurder dan EPS. Steenstrips als afwerking kosten €20–€40/m² meer dan crepi. Steigerkosten komen bovenop de prijs per m²."],bullets:["ETICS met EPS 60mm + crepi: €80–€110/m²","ETICS met EPS 100mm + crepi: €100–€130/m²","ETICS met minerale wol + crepi: €110–€150/m²","Steenstrips als afwerking: +€20–€40/m²"]},{title:"Welke voordelen merkt u in de praktijk?",paragraphs:["Naast de energiebesparing verbetert gevelisolatie ook het akoestisch comfort: de woning wordt stiller. Bovendien verdwijnen koudebruggen, wat condensatie en vochtproblemen aan de binnenkant vermindert.","Een betere EPC-score verhoogt ook de verkoopwaarde van uw woning. Zeker bij verhuur is een goede EPC-score steeds belangrijker door de Vlaamse renovatieverplichting."],bullets:["20–35% minder warmteverlies via de gevel","Betere EPC-score en hogere woningwaarde","Minder condensatie en vochtproblemen","Verbeterd akoestisch comfort","Geen verlies van binnenruimte"]},{title:"Premies voor gevelisolatie in 2026",paragraphs:["Via de Vlaamse Mijn VerbouwPremie kunt u een deel van de kosten recupereren als de isolatielaag minimaal Rd 3 m²K/W haalt (ca. 80–100mm EPS). Het premiebedrag hangt af van uw inkomen en de oppervlakte.","Combineer gevelisolatie met ramen of dakisolatie voor een hogere totaalpremie. Wij bezorgen u alle vereiste attesten en facturen voor een vlotte premieaanvraag."]}],ctaTitle:"Gevelisolatie laten plaatsen?",ctaText:"Yannova komt ter plaatse opmeten en bezorgt u een gedetailleerde offerte voor gevelisolatie, crepi of een complete gevelrenovatie.",relatedSlugs:["crepi-prijs-per-m2","hoeveel-kost-gevelrenovatie","energie-renovatie-premie-belgie"]},{slug:"renovatie-premies-vlaanderen-2026",title:"Renovatie premies Vlaanderen 2026: volledig overzicht",excerpt:"Welke renovatiepremies zijn er in Vlaanderen in 2026? Overzicht van Mijn VerbouwPremie, Mijn VerbouwLening en andere subsidies.",description:"Volledig overzicht van renovatiepremies in Vlaanderen 2026: Mijn VerbouwPremie, Mijn VerbouwLening, REG-premies en lokale subsidies voor ramen, gevel en isolatie.",date:"2026-03-13",readTime:"8 min",category:"Premies",keywords:["renovatie premies vlaanderen 2026","mijn verbouwpremie 2026","premies renovatie 2026","verbouwpremie vlaanderen","renovatie subsidie belgie"],serviceTags:["renovatie","ramen-deuren","gevelrenovatie","crepi-gevel","totaalrenovatie"],dynamic:!0,intro:"Renoveren in Vlaanderen loont in 2026 meer dan ooit. De Mijn VerbouwPremie, Mijn VerbouwLening en REG-premies maken energetische renovaties financieel aantrekkelijker. Dit is het volledige overzicht.",keyPoints:["Mijn VerbouwPremie: voor ramen, gevelisolatie, dakisolatie en meer","Mijn VerbouwLening: voordelig rentetarief voor energetische renovaties","REG-premies via uw netbeheerder voor specifieke werken","Combineer premies slim voor maximale terugbetaling"],sections:[{title:"Mijn VerbouwPremie: de belangrijkste subsidie",paragraphs:["De Mijn VerbouwPremie is de centrale Vlaamse renovatiepremie voor woningeigenaars en verhuurders. Ze dekt een deel van de kosten voor energetische ingrepen aan de buitenschil: dakisolatie, gevelisolatie, vloerisolatie, ramen en deuren.","Het premiebedrag hangt af van uw inkomen (lager inkomen = hogere premie) en de oppervlakte of het aantal eenheden. U vraagt de premie aan via het Mijn VerbouwPremie-portaal na uitvoering van de werken."],bullets:["Ramen en deuren: premie bij vervanging door HR++ of beter","Gevelisolatie: premie bij min. Rd 3 m²K/W (ca. 80–100mm EPS)","Dakisolatie: premie bij min. Rd 4,5 m²K/W","Vloerisolatie: premie bij min. Rd 1,5 m²K/W"]},{title:"Mijn VerbouwLening: voordelig lenen voor renovatie",paragraphs:["Naast de premie kunt u ook een Mijn VerbouwLening aanvragen bij het Vlaams Energiebedrijf (VEB). Dit is een lening aan een voordelig rentetarief voor energetische renovaties.","De lening is interessant als u meerdere werken combineert of als de premie niet voldoende is om de investering te financieren. Het tarief is lager dan een gewone banklening."]},{title:"REG-premies via uw netbeheerder",paragraphs:["Naast de Vlaamse premies bieden netbeheerders (Fluvius) ook REG-premies (Rationeel Energiegebruik) voor specifieke werken. Deze worden automatisch verrekend via uw installateur of aannemer.","REG-premies zijn beschikbaar voor onder meer hoogrendementsglas, warmtepompen en zonnepanelen. Ze worden gecombineerd met de Mijn VerbouwPremie."]},{title:"Lokale premies in Antwerpen en omgeving",paragraphs:["Naast de Vlaamse premies hebben sommige gemeenten en de stad Antwerpen eigen subsidies voor renovatie. Deze zijn vaak gericht op specifieke doelgroepen of wijken.","Informeer bij uw gemeente of er lokale premies beschikbaar zijn voor uw renovatieproject. Wij helpen u graag de juiste documenten op te stellen."]},{title:"Hoe combineert u premies slim?",paragraphs:["De slimste aanpak is om meerdere energetische ingrepen te combineren in één project. Zo kunt u voor elk onderdeel (ramen, gevel, dak) een aparte premie aanvragen.","Bewaar alle facturen, attesten en technische fiches zorgvuldig. Wij bezorgen u bij elk project de nodige documenten voor een vlotte premieaanvraag."],bullets:["Combineer ramen + gevelisolatie + dakisolatie voor maximale premie","Vraag premies aan per onderdeel, niet als totaalproject","Bewaar alle facturen en technische attesten","Vraag ook naar de Mijn VerbouwLening voor het resterende bedrag"]},{title:"Wat verandert er in 2026?",paragraphs:["De Vlaamse renovatieverplichting wordt strenger: woningen met EPC-label E of F die verkocht worden, moeten binnen 5 jaar gerenoveerd worden naar label D of beter. Dit maakt energetische renovatie niet alleen financieel interessant, maar ook steeds meer verplicht.","De premies voor 2026 zijn grotendeels ongewijzigd ten opzichte van 2025, maar de drempelwaarden voor isolatie worden strenger. Informeer tijdig over de actuele voorwaarden."]}],ctaTitle:"Weten welke premies u kunt aanvragen?",ctaText:"Yannova helpt u graag de juiste premies te identificeren en bezorgt u alle nodige attesten en facturen voor een vlotte aanvraag.",relatedSlugs:["energie-renovatie-premie-belgie","gevelisolatie-prijs-voordelen","crepi-prijs-per-m2"]},{slug:"wat-kosten-nieuwe-ramen",title:"Wat kosten nieuwe ramen in 2026?",excerpt:"Ontdek de prijzen voor PVC en aluminium ramen en waar de prijs van afhangt.",description:"Ontdek de prijzen voor nieuwe ramen in 2026. PVC ramen vanaf €400/m², aluminium vanaf €600/m². Inclusief plaatsing en BTW.",date:"2026-03-08",readTime:"5 min",category:"Prijzen",keywords:["ramen prijzen","wat kosten ramen","pvc ramen prijs","aluminium ramen prijs"],serviceTags:["ramen-deuren"]},{slug:"premies-ramen-deuren-2026",title:"Premies voor ramen en deuren in 2026",excerpt:"Overzicht van alle beschikbare premies in Vlaanderen voor nieuwe ramen en deuren.",description:"Overzicht van alle beschikbare premies in Vlaanderen voor nieuwe ramen en deuren.",date:"2026-03-08",readTime:"7 min",category:"Premies",keywords:["premies ramen deuren","ramen premie","deuren premie","mijn verbouwpremie"],serviceTags:["ramen-deuren"]},{slug:"pvc-of-aluminium-ramen",title:"PVC of aluminium ramen: wat is beter?",excerpt:"Vergelijk de voor- en nadelen van PVC en aluminium ramen voor uw woning.",description:"Vergelijk de voor- en nadelen van PVC en aluminium ramen voor uw woning.",date:"2026-03-08",readTime:"6 min",category:"Tips",keywords:["pvc of aluminium ramen","aluminium ramen","pvc ramen","ramen vergelijken"],serviceTags:["ramen-deuren"]},{slug:"energiebesparing-nieuwe-ramen",title:"Energiebesparing met nieuwe ramen",excerpt:"Bespaar tot 50% energie met HR++ glas. Bereken je terugverdientijd.",description:"Bespaar tot 50% energie met HR++ glas. Bereken je terugverdientijd.",date:"2026-03-09",readTime:"5 min",category:"Besparing",keywords:["energiebesparing ramen","hr++ glas besparen","ramen isolatie"],serviceTags:["ramen-deuren"]},{slug:"hoeveel-kost-gevelrenovatie",title:"Hoeveel kost gevelrenovatie in 2026?",excerpt:"Complete prijsoverzicht: €80-150/m² voor isolatie + crepi. Inclusief premies.",description:"Ontdek de prijzen voor gevelrenovatie met isolatie en crepi. Gemiddeld €80-150 per m². Inclusief premies en besparingen.",date:"2026-03-09",readTime:"6 min",category:"Prijzen",keywords:["gevelrenovatie prijs","kosten gevelrenovatie","crepi prijs","gevelisolatie kosten"],serviceTags:["gevelrenovatie","crepi-gevel"]}];function c(){return[...b].sort((a,b)=>b.date.localeCompare(a.date))}function d(a){return b.find(b=>b.slug===a)??null}function e(){return b.filter(a=>a.dynamic)}function f({currentSlug:a,serviceSlug:b,citySlug:d,limit:e=3}){return c().filter(b=>b.slug!==a).map(a=>{let c=0;return b&&a.serviceTags.includes(b)&&(c+=3),d&&a.cityTags?.includes(d)&&(c+=2),{post:a,score:c}}).sort((a,b)=>b.score!==a.score?b.score-a.score:b.post.date.localeCompare(a.post.date)).slice(0,e).map(a=>a.post)}a.s(["getBlogIndexPosts",()=>c,"getBlogPostBySlug",()=>d,"getDynamicBlogPosts",()=>e,"getRelatedBlogPosts",()=>f])}];

